100	// MountCLI returns a fresh, unattached Cobra root command. Most command paths
101	// are native Cobra commands; legacy compatibility remains for the default
102	// prompt path and explicitly delegated commands.
103	func MountCLI(opts ...MountOption) *cobra.Command {
104		cfg := mountConfig{
105			use:    productinfo.BinaryName,
106			short:  "Run the fiz CLI",
107			stdin:  os.Stdin,
108			stdout: os.Stdout,
109			stderr: os.Stderr,
110		}
111		for _, opt := range opts {
112			if opt != nil {
113				opt(&cfg)
114			}
115		}
116		if cfg.version != "" {
117			Version = cfg.version
118		}
119		if cfg.buildTime != "" {
120			BuildTime = cfg.buildTime
121		}
122		if cfg.gitCommit != "" {
123			GitCommit = cfg.gitCommit
124		}
125		cmd := &cobra.Command{
126			Use:           cfg.use,
127			Short:         cfg.short,
128			Long:          cfg.long,
129			SilenceUsage:  true,
130			SilenceErrors: true,
131			RunE: func(cmd *cobra.Command, args []string) error {
132				return runMounted(cfg, legacyArgs(cmd, args...))
133			},
134		}
135		addLegacyPersistentFlags(cmd)
136		addMountedSubcommands(cmd, cfg)
137		cmd.SetIn(cfg.stdin)
138		cmd.SetOut(cfg.stdout)
139		cmd.SetErr(cfg.stderr)
140		return cmd
141	}
