649	// NeedsLegacyPassthrough reports whether argv should bypass Cobra traversal
650	// until the corresponding command path has native pflag definitions.
651	func NeedsLegacyPassthrough(args []string) bool {
652		valueFlags := map[string]bool{
653			"--harness":   true,
654			"--max-power": true,
655			"--max-iter":  true,
656			"--min-power": true,
657			"--model":     true,
658			"--p":         true,
659			"-p":          true,
660			"--policy":    true,
661			"--preset":    true,
662			"--provider":  true,
663			"--reasoning": true,
664			"--system":    true,
665			"--work-dir":  true,
666		}
667		subcommands := map[string]bool{}
668		for _, name := range mountedSubcommands() {
669			subcommands[name] = true
670		}
671		for i := 0; i < len(args); i++ {
672			arg := args[i]
673			if strings.HasPrefix(arg, "-") {
674				if valueFlags[arg] && i+1 < len(args) {
675					i++
676				}
677				continue
678			}
679			if arg == "run" {
680				return false
681			}
682			switch arg {
683			case "log", "replay", "usage", "providers", "policies", "harnesses", "models", "check", "route-status", "corpus", "import", "update":
684				return false
685			case "cache":
686				if i+1 < len(args) && args[i+1] == "prune" {
687					return false
688				}
689				return true
690			case "catalog":
691				if i+1 < len(args) {
692					switch args[i+1] {
693					case "show", "models", "observations", "check", "update", "update-pricing":
694						return false
695					}
696				}
697				return true
698			default:
699				return subcommands[arg] || arg != ""
700			}
701		}
702		return false
703	}
